import React, { useState } from "react";
import { useLocation, useNavigate } from "react-router-dom";
import Navbar from "./Navbar";
import Footer from "./Footer";

function Appointment() {
  const location = useLocation();
  const navigate = useNavigate();

  const { doctor, date, time, doctor_id } = location.state || {};

  const [success, setSuccess] = useState(false);
  const [loading, setLoading] = useState(false);

  const handleConfirm = async () => {
    // ✅ Check date
    const today = new Date().toISOString().split("T")[0];
    if (date < today) {
      alert("Cannot book past dates");
      return;
    }

    // ✅ Check token
    const token = localStorage.getItem("token");
    if (!token) {
      alert("Please login first");
      navigate("/login");
      return;
    }

    setLoading(true);

    try {
      const response = await fetch("http://127.0.0.1:8000/book-appointment/", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Token ${token}`,
        },
        body: JSON.stringify({
          doctor_id: doctor_id,
          appointment_date: date,
          time_slot: time, // ✅ FIXED
        }),
      });

      const data = await response.json();

      // 🔍 DEBUG (VERY IMPORTANT)
      console.log("STATUS:", response.status);
      console.log("RESPONSE:", data);

      if (response.ok) {
        setSuccess(true);

        setTimeout(() => {
          navigate("/home"); // ✅ better route
        }, 2000);
      } else {
        alert(data.error || data.message || "Booking failed");
      }
    } catch (error) {
      console.error("FULL ERROR:", error);
      alert("Something went wrong - check console");
    } finally {
      setLoading(false);
    }
  };

  // ❌ If user refresh page
  if (!doctor) {
    return <h2 style={{ textAlign: "center" }}>No appointment data</h2>;
  }

  return (
    <div style={styles.container}>
      <Navbar />

      <div style={styles.main}>
        <div style={styles.card}>
          <h2>Confirm Appointment</h2>

          <p><strong>Doctor:</strong> {doctor.name}</p>
          <p><strong>Date:</strong> {date}</p>
          <p><strong>Time:</strong> {time}</p>

          <button
            style={styles.button}
            onClick={handleConfirm}
            disabled={loading}
          >
            {loading ? "Booking..." : "Confirm Booking"}
          </button>

          {success && (
            <p style={styles.success}>
              ✅ Appointment booked successfully!
            </p>
          )}
        </div>
      </div>

      <Footer />
    </div>
  );
}

export default Appointment;

const styles = {
  container: {
    display: "flex",
    flexDirection: "column",
    minHeight: "100vh",
    backgroundColor: "#f4f6f9",
    fontFamily: "Arial, sans-serif",
  },

  main: {
    flex: 1,
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
  },

  card: {
    backgroundColor: "white",
    padding: "30px",
    borderRadius: "10px",
    width: "400px",
    textAlign: "center",
    boxShadow: "0 4px 12px rgba(0,0,0,0.1)",
  },

  button: {
    marginTop: "20px",
    padding: "10px",
    width: "100%",
    backgroundColor: "#2c3e50",
    color: "white",
    border: "none",
    borderRadius: "5px",
    cursor: "pointer",
  },

  success: {
    marginTop: "15px",
    color: "green",
    fontWeight: "bold",
  },
};
